class Solution {
public:
    vector<string> uncommonFromSentences(string s1, string s2) {
        unordered_map<string, int> count;
        istringstream iss1(s1), iss2(s2);
        string word;
        while (iss1 >> word) count[word]++;
        while (iss2 >> word) count[word]++;
        vector<string> result;
        for (auto& pair : count) {
            if (pair.second == 1) result.push_back(pair.first);
        }
        return result;
    }
};
efficiency: HIGH
time complexity: O(n + m)
space complexity: O(n + m)
energy implications: LOW
explanation: Uses an unordered_map to count word occurrences in both sentences, then iterates over the map to find words that appear exactly once, achieving a linear time complexity.
